VALUES
  ('optician-moex-00739', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '患者之屈光度為-3.50DS，角膜弧度為7.7mm，若使用基弧7.85mm的硬式隱形眼鏡矯正，則隱形眼鏡之 屈光度應為何？', '["-2.75DS", "-3.25DS", "-3.75DS", "-4.25DS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00740', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關選擇透氣硬式隱形眼鏡（RGP）之直徑，下列各項參考因素之敘述何者錯誤？', '["瞳孔大小（pupilsize,PS）再加3.5~4.0mm等於後光學區直徑（BOZD）時，直徑建議選擇後光學區直 徑（BOZD）加上1.2~1.4mm之大小", "水平虹膜直徑（HVID）大於12.5mm，直徑建議選擇9.0~9.3mm", "瞼裂（palpebralaperture,PA）小於8.0mm，直徑建議選擇9.0~9.3mm", "瞼裂大於11.5mm，直徑建議選擇9.7~9.9mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00741', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜弧度測量（keratometry），下列敘述何者錯誤？', '["傳統的角膜弧度儀（keratometer）可以測量角膜中心頂點（apex），無法測量周邊角膜的弧度", "角膜的弧度，以曲率半徑，單位為釐米（mm）或K值（屈光度）來表示", "使用同心環圓盤系統 Placido disc 測量角膜曲率，是由投射在角膜前表面的反射影像，運用公式計算出 來的", "角膜弧度儀可以測量角膜曲率、角膜散光及散光軸度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00742', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種隱形眼鏡併發症較不會有疼痛感產生？', '["微生物性角膜炎（microbialkeratitis）", "黏蛋白球（mucinballs）", "隱形眼鏡急性紅眼症（contactlensacuteredeye,CLARE）", "角膜上皮皺褶（cornealepithelialwrinkle）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00743', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '巨大乳突性結膜炎不宜以下那種處置來獲得改善？', '["頻繁更換鏡片", "強效類固醇", "抗組織胺", "減少配戴時間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00744', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關鞏膜鏡片配戴的問題和併發症敘述，下列何者錯誤？', '["黏液會累積在角膜前區", "配戴鞏膜鏡片不常發生眼睛感染的問題", "結膜變白與充血表示鞏膜區有壓迫性的接觸", "鏡片後方所形成的氣泡可以使用擠壓鏡片方式使其完全消失"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00745', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '角膜變形（corneal warpage）可能發生於隱形眼鏡配戴者之角膜，發生角膜變形主要是由於角膜當中的那 一層產生改變？', '["角膜上皮層（cornealepithelium）", "德士密氏膜（Descemet’smembrane）", "角膜基質層（cornealstroma）", "內皮細胞層（cornealendothelium）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00746', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡併發症之敘述，下列何者錯誤？', '["隱形眼鏡誘發之乳突狀結膜炎（contactlenspapillaryconjunctivitis,CLPC）較常發生在延長配戴型矽水膠 隱形眼鏡配戴者中", "角膜上側上皮弧形損傷（superiorepitheliumarcuatelesions,SEALs）會有點狀螢光染色發生", "微生物性角膜炎（microbialkeratitis）可能會導致視力缺損", "角膜新生血管（cornealneovascularization）較常發生在延長配戴型水膠隱形眼鏡配戴者中"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00747', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若配戴較緊的鞏膜硬式隱形眼鏡，則利用裂隙燈檢查時會發現患者眼部在下列何處會有壓迫痕跡？', '["角膜周邊", "角膜頂點", "結膜靠近輪部的地方", "結膜靠近中周邊的地方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00748', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於上輪部角結膜炎（superiorlimbickeratoconjunctivitis）的敘述，下列何者錯誤？', '["是一種慢性且局部的角膜結膜發炎疾病", "上輪部角結膜炎的症狀主要是眼紅、異物感與灼熱感", "通常以單眼發作為主", "症狀輕微者（第二級以下），建議停戴隱形眼鏡2-4週"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
